// Translate the node so it can't be seen on the screen.
// Later, we're going to translate the node back to its original location with `none`.
function getTranslateValue(direction, node, container) {
  const rect = node.getBoundingClientRect();
  const containerRect = container && container.getBoundingClientRect();
  const containerWindow = ownerWindow(node);
  let transform;

  if (node.fakeTransform) {
    transform = node.fakeTransform;
  } else {
    const computedStyle = containerWindow.getComputedStyle(node);
    transform =
      computedStyle.getPropertyValue('-webkit-transform') ||
      computedStyle.getPropertyValue('transform');
  }

  let offsetX = 0;
  let offsetY = 0;

  if (transform && transform !== 'none' && typeof transform === 'string') {
    const transformValues = transform.split('(')[1].split(')')[0].split(',');
    offsetX = parseInt(transformValues[4], 10);
    offsetY = parseInt(transformValues[5], 10);
  }

  if (direction === 'left') {
    return `translateX(${
      containerRect ? containerRect.right : containerWindow.innerWidth
    }px) translateX(${offsetX - rect.left}px)`;
  }

  if (direction === 'right') {
    return `translateX(-${
      rect.left + rect.width - offsetX - (containerRect ? containerRect.left : 0)
    }px)`;
  }

  if (direction === 'up') {
    return `translateY(${
      containerRect ? containerRect.bottom : containerWindow.innerHeight
    }px) translateY(${offsetY - rect.top}px)`;
  }

  // direction === 'down'
  return `translateY(-${
    rect.top + rect.height - offsetY - (containerRect ? containerRect.top : 0)
  }px)`;
}

export function setTranslateValue(direction, node, container) {
  const transform = getTranslateValue(direction, node, container);

  if (transform) {
    node.style.webkitTransform = transform;
    node.style.transform = transform;
  }
}

